class ListNode:
    def __init__(self, val=0, next=None):
        self.val = val
        self.next = next

def merge_two_lists(l1, l2):
    dummy = ListNode()
    tail  = dummy
    while l1 and l2:
        if l1.val <= l2.val:
            tail.next = l1
            l1        = ___________
        else:
            tail.next = l2
            l2        = ___________
        tail = tail.next
    tail.next = l1 if l1 else l2
    return dummy.next
